/** URL query `?mode=edit` — list → detail edit intent (bookmarkable). */

export const FORM_URL_MODE_PARAM = 'mode';
export const FORM_URL_MODE_EDIT = 'edit';

export interface FormNavigateEditIntent {
  startInEditMode?: boolean;
}

export function isFormUrlEditMode(search: string): boolean {
  const raw = search.startsWith('?') ? search.slice(1) : search;
  return new URLSearchParams(raw).get(FORM_URL_MODE_PARAM)?.toLowerCase() === FORM_URL_MODE_EDIT;
}

export function withFormEditModeSearch(search: string): string {
  const raw = search.startsWith('?') ? search.slice(1) : search;
  const params = new URLSearchParams(raw);
  params.set(FORM_URL_MODE_PARAM, FORM_URL_MODE_EDIT);
  const q = params.toString();
  return q ? `?${q}` : '';
}

export function withoutFormEditModeSearch(search: string): string {
  const raw = search.startsWith('?') ? search.slice(1) : search;
  const params = new URLSearchParams(raw);
  params.delete(FORM_URL_MODE_PARAM);
  const q = params.toString();
  return q ? `?${q}` : '';
}

/** List navigate state and/or `?mode=edit` — both mean open detail in Edit. */
export function shouldStartFormInEditMode(
  search: string,
  state: FormNavigateEditIntent | null | undefined,
): boolean {
  return isFormUrlEditMode(search) || state?.startInEditMode === true;
}
