import type { SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import { createStaticLookupSearchConfig } from '../../../../../components/search';
import type { CompanyBankAccountDto } from '../../../../../services/kt/models';

export function formatCompanyBankDisplay(account?: CompanyBankAccountDto | null): string {
  if (!account) return '';
  const bank = account.bankName?.trim() ?? '';
  const branch = account.branchName?.trim() ?? '';
  if (bank && branch) return `${bank} — ${branch}`;
  return bank || branch || account.name || '';
}

export function createCompanyBankAccountSearchConfig(
  accounts: CompanyBankAccountDto[],
  departmentCode?: string,
): SearchInputConfig<CompanyBankAccountDto> {
  const filtered = departmentCode
    ? accounts.filter(a => (a.departmentCode ?? '') === departmentCode)
    : accounts;

  return createStaticLookupSearchConfig({
    loadItems: () => filtered,
    getKey: a => a.code,
    getCode: a => a.accountNumber || a.code,
    getName: a => formatCompanyBankDisplay(a),
    getFilterText: a =>
      `${a.code} ${a.accountNumber} ${a.name} ${a.bankName} ${a.branchName} ${a.departmentCode ?? ''}`,
    codeHeaderLabel: 'STK / Mã',
    nameHeaderLabel: 'Ngân hàng — Chi nhánh',
  });
}
