import React, { useEffect, useMemo, useRef, useState } from 'react';
import {
  Input,
  Select,
  MoneyInput,
  LabelMoney,
  SearchInput,
  dispatchAppToast,
} from '@linm-soft-org/linm-web-common-components';
import { useLocation } from 'react-router-dom';
import { useInAppNavigate } from '../../../../../router/useInAppNavigate';
import { useAppDispatch } from '../../../../../store/hooks';
import {
  FormMode,
  effectiveFormMode,
  fieldPlaceholder,
  initialFormMode,
  isEditingMode,
  useFormEmbedSlideout,
  useFormFieldLock,
  useFormRouteId,
  useTopbarAutoHideOnScroll,
  useVoucherFormShellHeight,
} from '../../../../../components/form';
import {
  VoucherFormToolbar,
  VoucherPostedLedgerModal,
  VoucherFormStatusGroup,
} from '../../../../../components/voucher';
import { useVoucherInitData } from '../../../../../hooks/useVoucherInitData';
import { useUnsavedChangesGuard } from '../../../../../hooks/useUnsavedChangesGuard';
import { getApiErrorMessage } from '../../../../../utils/getApiErrorMessage';
import { pollDocumentPostingStatus } from '../../../../../utils/pollDocumentPostingStatus';
import { resolveProcessingLevelSelectOptions, formatProcessingLevelFromOptions } from '../../../../../utils/voucherProcessingLevelOptions';
import {
  buildVoucherToolbarDisabledReasons,
  isVoucherFormStatusLocked,
  resolveVoucherViewModeHint,
} from '../../../../../utils/voucherProcessingLevelDisplay';
import { resolveVoucherFormToolbarFlags } from '../../../../../utils/resolveVoucherFormToolbarFlags';
import { BANK_TRANSFER_CONFIG } from '../config/bankTransferConfig';
import { bankTransferLabels } from '../../../../../constants/bankTransferLabels';
import { bankTransferInitFormName } from '../../../../../constants/bankTransferInit';
import { TRANSFER_REASON_OPTIONS } from '../../../../../constants/transferReasonLabels';
import type { DocumentPostingStatus, CompanyBankAccountDto } from '../../../../../services/kt/models';
import { ktService } from '../../../../../services/kt/ktService';
import {
  buildBankTransferSavePayload,
  defaultBankTransferFormState,
  mapDtoToBankTransferForm,
  serializeBankTransferSnapshot,
  type BankTransferFormState,
} from '../mappers/bankTransferMappers';
import {
  createCompanyBankAccountSearchConfig,
  formatCompanyBankDisplay,
} from '../search/companyBankAccountSearchConfig';
import styles from '../../../../../styles/documentForm.module.css';

export const BankTransferFormParent: React.FC = () => {
  const id = useFormRouteId();
  const isNew = !id;
  const dispatch = useAppDispatch();
  const navigate = useInAppNavigate();
  const location = useLocation();
  const shellRef = useRef<HTMLDivElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const embedSlideout = useFormEmbedSlideout();
  useVoucherFormShellHeight(shellRef, !embedSlideout);
  useTopbarAutoHideOnScroll(scrollRef, !embedSlideout);

  const initFormName = bankTransferInitFormName(isNew);
  const { processingLevelOptions, formPermissions, initError, loading: initLoading } = useVoucherInitData(initFormName);

  const [formMode, setFormMode] = useState<FormMode>(() => {
    if (isNew) return FormMode.Create;
    const startEdit = (location.state as { startInEditMode?: boolean } | null)?.startInEditMode;
    return startEdit ? FormMode.Edit : FormMode.View;
  });
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [voucherCode, setVoucherCode] = useState('');
  const [status, setStatus] = useState('Draft');
  const [formState, setFormState] = useState<BankTransferFormState>(defaultBankTransferFormState);
  const [savedSnapshot, setSavedSnapshot] = useState<string | null>(null);
  const [companyBankAccounts, setCompanyBankAccounts] = useState<CompanyBankAccountDto[]>([]);
  const [departmentFilter, setDepartmentFilter] = useState('');
  const [postingStatus, setPostingStatus] = useState<DocumentPostingStatus>('None');
  const [showLedgerModal, setShowLedgerModal] = useState(false);
  const [headerExpanded, setHeaderExpanded] = useState(true);

  const toolbarMode = effectiveFormMode(isNew, formMode);
  const isStatusLocked = isVoucherFormStatusLocked(status, formState.processingLevel);
  const {
    fieldLockProps,
    staticFieldProps,
    selectDisabled,
    textareaReadOnly,
    viewSectionClass,
  } = useFormFieldLock({
    formMode: toolbarMode,
    isStatusLocked,
  });

  const listPath = useMemo(() => {
    if (typeof window !== 'undefined' && window.location.pathname.startsWith(BANK_TRANSFER_CONFIG.listPathAlias)) {
      return BANK_TRANSFER_CONFIG.listPathAlias;
    }
    return BANK_TRANSFER_CONFIG.listPath;
  }, []);

  const readOnly = !isEditingMode(formMode);
  const isViewMode = formMode === FormMode.View;
  const isDirty = savedSnapshot != null && serializeBankTransferSnapshot(formState) !== savedSnapshot;
  useUnsavedChangesGuard(isDirty, isEditingMode(toolbarMode));

  const bankAccountByCode = useMemo(
    () => new Map(companyBankAccounts.map(item => [item.code, item])),
    [companyBankAccounts],
  );

  const departmentOptions = useMemo(() => {
    const codes = [...new Set(
      companyBankAccounts
        .map(a => a.departmentCode?.trim())
        .filter((c): c is string => !!c),
    )].sort();
    return [
      { value: '', label: bankTransferLabels.departmentFilterAll },
      ...codes.map(c => ({ value: c, label: c })),
    ];
  }, [companyBankAccounts]);

  const filteredBankAccounts = useMemo(
    () => (departmentFilter
      ? companyBankAccounts.filter(a => (a.departmentCode ?? '') === departmentFilter)
      : companyBankAccounts),
    [companyBankAccounts, departmentFilter],
  );

  const fromBankSearchConfig = useMemo(
    () => createCompanyBankAccountSearchConfig(filteredBankAccounts),
    [filteredBankAccounts],
  );

  const toBankSearchConfig = useMemo(
    () => createCompanyBankAccountSearchConfig(filteredBankAccounts),
    [filteredBankAccounts],
  );

  const selectedFromBank = bankAccountByCode.get(formState.fromBankAccountCode);
  const selectedToBank = bankAccountByCode.get(formState.toBankAccountCode);

  const displayFromAccountCode =
    formState.fromAccountCode || selectedFromBank?.glAccountCode || '';
  const displayToAccountCode =
    formState.toAccountCode || selectedToBank?.glAccountCode || '';

  const isVayTransfer = formState.transferReasonCode === 'CTNB-VAY';

  const processingOptions = resolveProcessingLevelSelectOptions(processingLevelOptions);

  const toolbarFlags = useMemo(
    () =>
      resolveVoucherFormToolbarFlags({
        formPermissions,
        isNew,
        status,
        processingLevel: formState.processingLevel,
        voucherDate: formState.voucherDate,
        id,
        postingStatus,
        enableApproveToolbar: false,
      }),
    [
      formPermissions,
      isNew,
      status,
      formState.processingLevel,
      formState.voucherDate,
      id,
      postingStatus,
    ],
  );

  const ph = (text: string) => fieldPlaceholder(toolbarMode, text, { isStatusLocked });

  const compactHideClass = (visibleWhenCompact: boolean) =>
    !headerExpanded && !visibleWhenCompact ? styles.headerCompactHidden : undefined;

  useEffect(() => {
    let cancelled = false;
    const timer = setTimeout(() => {
      ktService
        .getCompanyBankAccounts({ isActive: true, pageSize: 500 })
        .then(items => {
          if (cancelled) return;
          setCompanyBankAccounts(items);
        })
        .catch(() => {
          if (cancelled) return;
          dispatchAppToast(dispatch, {
            type: 'warning',
            message: 'Không tải được danh mục TK ngân hàng, vui lòng kiểm tra thiết lập dm/tai-khoan-ngan-hang.',
          });
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(timer);
    };
  }, [dispatch]);

  useEffect(() => {
    if (!id) {
      const initial = defaultBankTransferFormState();
      setFormState(initial);
      setSavedSnapshot(serializeBankTransferSnapshot(initial));
      return;
    }
    let cancelled = false;
    setLoading(true);
    const timer = setTimeout(() => {
      BANK_TRANSFER_CONFIG.get(id)
        .then(dto => {
          if (cancelled) return;
          const mapped = mapDtoToBankTransferForm(dto);
          setVoucherCode(dto.code);
          setStatus(dto.status);
          setFormState(mapped);
          setSavedSnapshot(serializeBankTransferSnapshot(mapped));
          if (!isNew && (location.state as { startInEditMode?: boolean } | null)?.startInEditMode) {
            setFormMode(FormMode.Edit);
          } else if (!isNew) {
            setFormMode(FormMode.View);
          }
        })
        .catch(error => {
          if (cancelled) return;
          dispatchAppToast(dispatch, {
            type: 'error',
            message: getApiErrorMessage(error, bankTransferLabels.loadError),
          });
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);

    return () => {
      cancelled = true;
      clearTimeout(timer);
    };
  }, [id, dispatch, isNew, location.state]);

  useEffect(() => {
    if (!formState.processingLevel && processingLevelOptions.length > 0) {
      setFormState(prev => ({
        ...prev,
        processingLevel: prev.processingLevel || String(processingLevelOptions[0].value),
      }));
    }
  }, [processingLevelOptions, formState.processingLevel]);

  const updateField = <K extends keyof BankTransferFormState>(key: K, value: BankTransferFormState[K]) => {
    setFormState(prev => ({ ...prev, [key]: value }));
  };

  const pollPostingIfNeeded = async (voucherId: string, level: string) => {
    if (level !== '9') return;
    try {
      const final = await pollDocumentPostingStatus(() => BANK_TRANSFER_CONFIG.getPostingStatus(voucherId));
      setPostingStatus(final.postingStatus);
    } catch {
      setPostingStatus('Failed');
    }
  };

  const handleSave = async () => {
    if (!formState.fromBankAccountCode || !formState.toBankAccountCode) {
      dispatchAppToast(dispatch, {
        type: 'error',
        message: 'Vui lòng chọn tài khoản đi và tài khoản đến',
      });
      return;
    }
    if (formState.fromBankAccountCode === formState.toBankAccountCode) {
      dispatchAppToast(dispatch, {
        type: 'error',
        message: 'Tài khoản đi và tài khoản đến phải khác nhau',
      });
      return;
    }
    if (!formState.amount || formState.amount <= 0) {
      dispatchAppToast(dispatch, {
        type: 'error',
        message: 'Số tiền chuyển phải lớn hơn 0',
      });
      return;
    }
    setSaving(true);
    try {
      const payload = buildBankTransferSavePayload({
        ...formState,
        fromPaymentChannelCode: selectedFromBank?.paymentChannelCode ?? formState.fromPaymentChannelCode,
        toPaymentChannelCode: selectedToBank?.paymentChannelCode ?? formState.toPaymentChannelCode,
      });
      if (isNew) {
        const created = await BANK_TRANSFER_CONFIG.create(payload);
        dispatchAppToast(dispatch, { type: 'success', message: bankTransferLabels.saveSuccessCreate });
        setHeaderExpanded(true);
        navigate(`${listPath}/${created.id}`);
      } else if (id) {
        const updated = await BANK_TRANSFER_CONFIG.update(id, payload);
        const mapped = mapDtoToBankTransferForm(updated);
        setVoucherCode(updated.code);
        setStatus(updated.status);
        setFormState(mapped);
        setSavedSnapshot(serializeBankTransferSnapshot(mapped));
        setFormMode(FormMode.View);
        setHeaderExpanded(true);
        dispatchAppToast(dispatch, { type: 'success', message: bankTransferLabels.saveSuccessUpdate });
        await pollPostingIfNeeded(id, updated.processingLevel);
      }
    } catch (error) {
      dispatchAppToast(dispatch, {
        type: 'error',
        message: getApiErrorMessage(error, bankTransferLabels.saveError),
      });
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async () => {
    if (!id) return;
    if (!window.confirm(bankTransferLabels.deleteConfirm)) return;
    setDeleting(true);
    try {
      await BANK_TRANSFER_CONFIG.remove(id);
      dispatchAppToast(dispatch, { type: 'success', message: bankTransferLabels.deleteSuccess });
      navigate(listPath);
    } catch (error) {
      dispatchAppToast(dispatch, {
        type: 'error',
        message: getApiErrorMessage(error, bankTransferLabels.deleteError),
      });
    } finally {
      setDeleting(false);
    }
  };

  const toolbarDisabledReasons = useMemo(
    () => ({
      ...buildVoucherToolbarDisabledReasons({
        isNew,
        status,
        showPostButton: false,
        isStatusLocked,
      }),
      save: !toolbarFlags.canSaveToolbar ? 'Không có quyền lưu chứng từ' : undefined,
    }),
    [isNew, status, isStatusLocked, toolbarFlags.canSaveToolbar],
  );

  if (initError) {
    return (
      <div className={styles.pageVoucher} data-testid="kt-ctnb-init-error">
        <div className={styles.formErrorMessage}>
          <p className={styles.formErrorTitle}>Không thể tải dữ liệu form</p>
          <p className={styles.formErrorDetail}>{initError}</p>
        </div>
      </div>
    );
  }

  if (initLoading || loading) {
    return (
      <div className={styles.formInitLoading} data-testid="kt-ctnb-form-init-loading">
        <div className={styles.formInitSpinner} />
        <p>{bankTransferLabels.loading}</p>
      </div>
    );
  }

  return (
    <div ref={shellRef} className={styles.pageVoucher} data-voucher-form-shell data-testid="kt-ctnb-form">
      {!embedSlideout && (
        <div className={styles.pageFormHeader}>
          <div className={styles.stickyTop}>
            <VoucherFormToolbar
              testIdPrefix={BANK_TRANSFER_CONFIG.testIdPrefix}
              title={isNew ? bankTransferLabels.createTitle : `${bankTransferLabels.title} — ${voucherCode || '...'}`}
              processingLevelBadge={
                !isNew ? (
                  <VoucherFormStatusGroup
                    processingLevelLabel={formatProcessingLevelFromOptions(
                      formState.processingLevel,
                      processingLevelOptions,
                    )}
                  />
                ) : undefined
              }
              formMode={toolbarMode}
              viewModeHint={resolveVoucherViewModeHint({
                formMode: toolbarMode,
                isNew,
                status,
                processingLevel: formState.processingLevel,
                canEditWhenView: toolbarFlags.canEditToolbar,
              })}
              showApproveButton={toolbarFlags.showApproveToolbar}
              showPostButton={false}
              canCopy={toolbarFlags.canCopyToolbar}
              canPrint={toolbarFlags.canPrintToolbar}
              showEditButton={toolbarFlags.showEditButton}
              showDeleteButton={toolbarFlags.showDeleteButton}
              canEdit={toolbarFlags.canEditToolbar}
              canDelete={toolbarFlags.canDeleteToolbar}
              canViewLedger={toolbarFlags.canViewLedgerToolbar}
              showNewButton={toolbarFlags.showNewButton}
              canSave={!deleting && toolbarFlags.canSaveToolbar}
              saving={saving}
              disabledReasons={toolbarDisabledReasons}
              onBack={() => navigate(listPath)}
              onApprove={() => {}}
              onPost={() => {}}
              onCopy={() => {}}
              onPrint={() => {}}
              onSearch={() => {}}
              onNew={() => navigate(`${listPath}/them`)}
              onEdit={() => setFormMode(FormMode.Edit)}
              onSave={() => { void handleSave(); }}
              onCancel={() => {
                if (isNew) {
                  navigate(listPath);
                } else {
                  setFormMode(FormMode.View);
                }
              }}
              onDelete={() => { void handleDelete(); }}
              onViewLedger={() => setShowLedgerModal(true)}
              insetShell
            />
          </div>
        </div>
      )}

      <div ref={scrollRef} className={styles.pageFormScroll} data-testid="kt-ctnb-form-scroll">
        <section
          className={[
            styles.section,
            viewSectionClass,
            !headerExpanded ? styles.headerCompactActive : undefined,
          ].filter(Boolean).join(' ')}
        >
          <div className={styles.sectionTitleRow}>
            <h2 className={styles.sectionTitle}>{bankTransferLabels.sectionHeader}</h2>
            <button
              type="button"
              className={styles.headerToggleBtn}
              data-testid={`${BANK_TRANSFER_CONFIG.testIdPrefix}-header-${headerExpanded ? 'collapse' : 'expand'}`}
              aria-expanded={headerExpanded}
              onClick={() => setHeaderExpanded(v => !v)}
            >
              <span className={styles.headerToggleIcon} aria-hidden>
                <i className={headerExpanded ? 'fas fa-chevron-up' : 'fas fa-chevron-down'} />
              </span>
              {headerExpanded ? bankTransferLabels.headerCollapse : bankTransferLabels.headerExpand}
            </button>
          </div>
          <div className={styles.row4}>
            <div className={`${styles.field} ${compactHideClass(true) ?? ''}`} data-testid="kt-ctnb-field-voucherDate">
              <label className={styles.label}>{bankTransferLabels.voucherDate} *</label>
              <Input
                type="date"
                value={formState.voucherDate}
                onChange={e => updateField('voucherDate', e.target.value)}
                {...fieldLockProps}
              />
            </div>
            {!isNew && (
              <div className={`${styles.field} ${compactHideClass(false) ?? ''}`} data-testid="kt-ctnb-field-voucherCode">
                <label className={styles.label}>{bankTransferLabels.colCode}</label>
                <Input value={voucherCode} {...staticFieldProps} readOnly />
              </div>
            )}
            <div className={`${styles.field} ${compactHideClass(false) ?? ''}`} data-testid="kt-ctnb-field-transferReasonCode">
              <label className={styles.label}>{bankTransferLabels.transferReasonCode} *</label>
              <Select
                value={formState.transferReasonCode}
                onChange={e => updateField('transferReasonCode', e.target.value)}
                options={TRANSFER_REASON_OPTIONS as unknown as Array<{ value: string; label: string }>}
                disabled={selectDisabled}
              />
            </div>
            <div className={`${styles.field} ${compactHideClass(false) ?? ''}`} data-testid="kt-ctnb-field-departmentFilter">
              <label className={styles.label}>{bankTransferLabels.departmentFilter}</label>
              <Select
                value={departmentFilter}
                onChange={e => setDepartmentFilter(e.target.value)}
                options={departmentOptions}
                disabled={selectDisabled}
              />
            </div>
            <div className={`${styles.field} ${compactHideClass(true) ?? ''}`} data-testid="kt-ctnb-field-fromBankAccountCode">
              <label className={styles.label}>{bankTransferLabels.fromBankAccountCode} *</label>
              <SearchInput
                config={fromBankSearchConfig}
                value={formState.fromBankAccountCode}
                primaryDisplay={selectedFromBank?.accountNumber || formState.fromBankAccountCode}
                onChange={item => {
                  updateField('fromBankAccountCode', item.code);
                  updateField('fromPaymentChannelCode', item.paymentChannelCode ?? '');
                  updateField('fromAccountCode', item.glAccountCode);
                }}
                onClear={() => {
                  updateField('fromBankAccountCode', '');
                  updateField('fromPaymentChannelCode', '');
                  updateField('fromAccountCode', '');
                }}
                showLabel={false}
                showSecondaryInput={false}
                disabled={selectDisabled}
                placeholder={ph('Chọn STK nguồn...')}
              />
            </div>
            <div className={`${styles.field} ${compactHideClass(true) ?? ''}`} data-testid="kt-ctnb-field-fromBankDisplay">
              <label className={styles.label}>{bankTransferLabels.bankDisplay}</label>
              <Input
                value={formatCompanyBankDisplay(selectedFromBank)}
                {...staticFieldProps}
                readOnly
              />
            </div>
            <div className={`${styles.field} ${compactHideClass(true) ?? ''}`} data-testid="kt-ctnb-field-toBankAccountCode">
              <label className={styles.label}>{bankTransferLabels.toBankAccountCode} *</label>
              <SearchInput
                config={toBankSearchConfig}
                value={formState.toBankAccountCode}
                primaryDisplay={selectedToBank?.accountNumber || formState.toBankAccountCode}
                onChange={item => {
                  updateField('toBankAccountCode', item.code);
                  updateField('toPaymentChannelCode', item.paymentChannelCode ?? '');
                  updateField('toAccountCode', item.glAccountCode);
                }}
                onClear={() => {
                  updateField('toBankAccountCode', '');
                  updateField('toPaymentChannelCode', '');
                  updateField('toAccountCode', '');
                }}
                showLabel={false}
                showSecondaryInput={false}
                disabled={selectDisabled}
                placeholder={ph('Chọn STK đích...')}
              />
            </div>
            <div className={`${styles.field} ${compactHideClass(true) ?? ''}`} data-testid="kt-ctnb-field-toBankDisplay">
              <label className={styles.label}>{bankTransferLabels.bankDisplay}</label>
              <Input
                value={formatCompanyBankDisplay(selectedToBank)}
                {...staticFieldProps}
                readOnly
              />
            </div>
            <div className={`${styles.field} ${compactHideClass(true) ?? ''}`} data-testid="kt-ctnb-field-amount">
              <label className={styles.label}>{bankTransferLabels.amount} *</label>
              <MoneyInput
                value={formState.amount}
                onChange={v => updateField('amount', v)}
                readOnly={readOnly}
                disabled={isStatusLocked && readOnly}
              />
            </div>
            {displayFromAccountCode && (
              <div className={`${styles.field} ${compactHideClass(false) ?? ''}`} data-testid="kt-ctnb-field-fromAccountCode-preview">
                <label className={styles.label}>{bankTransferLabels.fromAccountCode}</label>
                <Input value={displayFromAccountCode} {...staticFieldProps} readOnly />
              </div>
            )}
            {displayToAccountCode && (
              <div className={`${styles.field} ${compactHideClass(false) ?? ''}`} data-testid="kt-ctnb-field-toAccountCode-preview">
                <label className={styles.label}>{bankTransferLabels.toAccountCode}</label>
                <Input value={displayToAccountCode} {...staticFieldProps} readOnly />
              </div>
            )}
            <div className={`${styles.field} ${compactHideClass(false) ?? ''}`} data-testid="kt-ctnb-field-counterpartyName">
              <label className={styles.label}>{bankTransferLabels.counterpartyName}</label>
              <Input
                value={formState.counterpartyName ?? ''}
                onChange={e => updateField('counterpartyName', e.target.value)}
                placeholder={isVayTransfer ? bankTransferLabels.counterpartyNameVayHint : ph('')}
                {...fieldLockProps}
              />
            </div>
            <div className={`${styles.field} ${compactHideClass(false) ?? ''}`} data-testid="kt-ctnb-field-counterpartyBankAccount">
              <label className={styles.label}>{bankTransferLabels.counterpartyBankAccount}</label>
              <Input
                value={formState.counterpartyBankAccount ?? ''}
                onChange={e => updateField('counterpartyBankAccount', e.target.value)}
                placeholder={ph('')}
                {...fieldLockProps}
              />
            </div>
            {formState.legacyId && (
              <div className={`${styles.field} ${compactHideClass(false) ?? ''}`} data-testid="kt-ctnb-field-legacyId">
                <label className={styles.label}>{bankTransferLabels.legacyId}</label>
                <Input value={formState.legacyId} {...staticFieldProps} readOnly />
              </div>
            )}
            <div className={`${styles.field} ${styles.spanCol4} ${compactHideClass(false) ?? ''}`} data-testid="kt-ctnb-field-description">
              <label className={styles.label}>{bankTransferLabels.description}</label>
              <textarea
                className={styles.textarea}
                value={formState.description ?? ''}
                onChange={e => updateField('description', e.target.value)}
                readOnly={textareaReadOnly}
                disabled={isStatusLocked && readOnly}
              />
            </div>
          </div>
        </section>
      </div>

      <div className={styles.pageFormFooter} data-testid="kt-ctnb-form-footer">
        <div className={styles.footer}>
          <div className={styles.footerLeft}>
            <div className={styles.field} data-testid="kt-ctnb-field-processingLevel">
              <label className={styles.label}>{bankTransferLabels.processingLevel} *</label>
              <Select
                value={formState.processingLevel}
                onChange={e => updateField('processingLevel', e.target.value)}
                options={processingOptions}
                disabled={selectDisabled}
              />
            </div>
          </div>
          <div className={styles.footerRight}>
            <LabelMoney
              label={bankTransferLabels.totalAmount}
              value={formState.amount}
              variant="footer"
              data-testid="kt-ctnb-footer-totalAmount"
            />
          </div>
        </div>
      </div>

      {id && (
        <VoucherPostedLedgerModal
          isOpen={showLedgerModal}
          onClose={() => setShowLedgerModal(false)}
          voucherTitle={`${bankTransferLabels.title} — ${voucherCode}`}
          testIdPrefix={BANK_TRANSFER_CONFIG.testIdPrefix}
          fetchPostedLedger={() => BANK_TRANSFER_CONFIG.getPostedLedger(id)}
          fetchPostingStatus={() => BANK_TRANSFER_CONFIG.getPostingStatus(id)}
        />
      )}
    </div>
  );
};

export default BankTransferFormParent;
